import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "4": {
    "1": "<p><em>wayyōsîpû bənê yiśrāʾēl laʿăśôt hāraʿ bəʿênê YHWH</em> — 'And the sons of Israel again did the evil in the eyes of YHWH.' The verb <em>yāsap</em> (H3254, to add/do again) combined with the infinitive construct marks the resumptive formula that signals each new cycle of apostasy. <em>hāraʿ</em> (H7451, the evil) with the definite article suggests not just evil in general but the specific well-known evil — covenant apostasy and Canaanite worship. The Deuteronomic phrase <em>bəʿênê YHWH</em> (in the eyes of YHWH) frames the narrative theologically: Israel's actions are evaluated from the divine perspective, not merely by their temporal consequences.</p>",
    "2": "<p><em>wayyimkərēm YHWH bəyaḏ yāḇîn melek-kənaʿan</em> — 'YHWH sold them into the hand of Jabin king of Canaan.' <em>mākar</em> (H4376, to sell/deliver over) is stark commercial language for YHWH's judicial action — Israel has broken covenant, so YHWH sells them as one disposes of property. The Deuteronomic theology of covenant curses (Deut 28:68 threatens literal resale into slavery in Egypt) is operative: apostasy reverses the Exodus. <em>yaḏ</em> (H3027, hand/power) as the instrument of domination appears throughout Judges: 'into the hand of' marks transfer of sovereignty. Hazor was the major Canaanite city Josh had already burned (Josh 11:11) — its re-emergence shows the conquest's incompleteness when Israel fails to maintain covenant.</p>",
    "3": "<p><em>wayyiṣʿaqû bənê yiśrāʾēl ʾel-YHWH</em> — 'and the sons of Israel cried out to YHWH.' <em>ṣāʿaq</em> (H6817, to cry out in distress) is the technical term for Israel's prayer that triggers the judge cycle — it is the same verb used in Exod 2:23 when Israel cried out from Egyptian bondage. The pattern is deliberate: every judge cycle re-enacts a miniature exodus. Nine hundred iron chariots (<em>rekeb-barzel</em>) represent the technological superiority of Canaan — iron chariotry gave a decisive military advantage in the plains that Israel, as a highland people, could not match by conventional means.</p>",
    "4": "<p><em>wəḏəḇôrāh ʾiššāh nəḇîʾāh ʾēšet lappîḏôt hîʾ šōpəṭāh ʾet-yiśrāʾēl bāʿēt hahîʾ</em> — 'Now Deborah, a woman, a prophetess, wife of Lappidoth — she was judging Israel at that time.' Three designations accumulate: <em>ʾiššāh</em> (woman — the gender marker is deliberate, noting the unusual situation), <em>nəḇîʾāh</em> (H5031, prophetess — the feminine form of <em>nāḇîʾ</em>, one who speaks for God), and <em>šōpəṭ</em> (H8199, one who judges/rules). Deborah is the only judge in the book who exercises the civil-judicial function of the šōpəṭ before any military action — she holds court under the Palm of Deborah (v5). That the covenant people in this moment has a woman as their primary leader-prophet is the text's implicit critique of the men of that generation.</p>",
    "5": "<p><em>wəhîʾ yôšeḇet taḥat-tōmer dəḇôrāh</em> — 'and she was sitting under the Palm of Deborah.' <em>tōmer</em> (H8560, palm tree) is a landmark; <em>yāšaḇ</em> (H3427, to sit/dwell) in the context of a judge's court means holding session. The designation 'Palm of Deborah' (<em>tōmer dəḇôrāh</em>) becomes a toponym — the judge and her court fuse into the landscape's memory. The <em>bənê yiśrāʾēl</em> (sons of Israel) come up to her for judgment (<em>mišpāṭ</em> H4941), showing her as the legitimate covenant mediator in a period when male leadership has failed.</p>",
    "6": "<p><em>wattiślah watiqqrāʾ ləḇārāq bin-ʾăḇînoʿam</em> — 'and she sent and called for Barak son of Abinoam.' The verb sequence — <em>šālaḥ</em> (H7971, to send) + <em>qārāʾ</em> (H7121, to call) — is the commissioning formula. Deborah does not wait to be consulted; she initiates. Her command to Barak quotes a direct divine imperative: <em>hălōʾ ṣiwwāh YHWH ʾĕlōhê yiśrāʾēl</em> — 'Has not YHWH the God of Israel commanded?' She positions herself as transmitter of the divine word — the prophetic function. Tabor (<em>har tāḇôr</em>) as the rallying point is the prominent northeastern hill that dominates the Jezreel Valley, visible from great distances.</p>",
    "7": "<p><em>wəmāšaktî ʾēlêkā ʾel-naḥal qîšôn ʾet-sîsərāʾ śar-ṣəḇāʾ yāḇîn</em> — 'I will draw (<em>māšak</em>) to you, to the Kishon river, Sisera the commander of Jabin's army.' <em>māšak</em> (H4900, to draw/drag/lead) is used here of divine military strategy: YHWH will lure the enemy to the terrain of his choosing. The Kishon riverbed plain, which floods when rains come, is precisely where iron chariots become useless. YHWH designs the battlefield. <em>ûnəṯattîhû bəyāḏekā</em> — 'and I will give him into your hand' — the prophetic oracle announces the victory in advance, making Barak's obedience a matter of trusting the divine word over present appearances.</p>",
    "8": "<p><em>wayyōʾmer ʾēlêhā bārāq ʾim-tēlkî ʿimmî wəhālāktî</em> — 'Barak said to her: If you go with me, I will go; but if you will not go with me, I will not go.' Barak's condition is sometimes read as cowardice, but his insistence on the prophet's presence is theologically coherent — the <em>malʾak YHWH</em> accompaniment in earlier deliverances (Exod 14:19) ensured divine presence. Deborah IS the divine word for this campaign. His condition acknowledges that victory depends on YHWH's presence, not military strength. The consequence (v9) reframes his condition as missed honor rather than disobedience.</p>",
    "9": "<p><em>wayyōʾmer wālōk ʾēlēk ʿimmāk ʾepes kî lōʾ-tihyeh tipʾartəkā ʿal-haddereḵ ʾăšer ʾattāh hôlēk</em> — 'She said: I will surely go with you; but the road you are going on will not lead to your glory (<em>tipʾāret</em>).' <em>tipʾāret</em> (H8597, glory/splendor/honor) is the prize that will be transferred: Sisera will fall to a woman. The statement functions as prophetic oracle delivered through irony — Barak's condition for going (the woman must come) becomes the condition for losing the honor (a woman will get the kill). <em>kî-bəyaḏ-ʾiššāh yimkōr YHWH ʾet-sîsərāʾ</em> — 'for YHWH will sell Sisera into the hand of a woman.' The verb <em>mākar</em> (H4376, to sell) from v2 recurs — just as YHWH sold Israel into Jabin's hand, now YHWH will sell Sisera into a woman's hand.</p>",
    "10": "<p><em>wayyazʿēq bārāq ʾet-zəḇûlun wəʾet-naptālî qāḏəšāh</em> — 'Barak called out Zebulun and Naphtali to Kedesh.' <em>zāʿaq</em> (H2199, to call out/muster — the same root as the cry of distress) here takes on its military connotation: the assembly call. Ten thousand men went up at his feet (<em>bəraglāyw</em> — at his heels, a military idiom for following in formation). Zebulun and Naphtali are the tribes of the northern heartland around Galilee — the territory most directly under Jabin's oppression (Hazor was in Naphtali territory). Deborah went up with him, completing the oracle's precondition.</p>",
    "11": "<p><em>wəḥeḇer haqqênî niprāḏ miqayin</em> — 'Now Heber the Kenite had separated from Midian.' <em>pāraḏ</em> (H6504, to separate/divide) — the notice of Heber's separation from his kinsmen and encampment at the Elon-bezaanannim near Kedesh is a planted narrative detail: it explains how Sisera knows where to flee for safety. <em>qênî</em> (H7017, Kenite) — the Kenites were the clan of Moses's father-in-law (1:16), carrying a history of covenant loyalty to Israel; yet here their loyalty is complicated by Heber's peace with Jabin (v17). The geographical detail (<em>ʾēlôn bəṣaʿananîm</em>, the oak of Zaanannim) anchors the story: this specific tree will be the site of Sisera's death.</p>",
    "12": "<p><em>wayyaggîḏû ləsîsərāʾ kî ʿālāh bārāq bin-ʾăḇînoʿam har-tāḇôr</em> — 'They told Sisera that Barak son of Abinoam had gone up to Mount Tabor.' Intelligence reaches Sisera through his network — the verb <em>nāgaḏ</em> (H5046, to tell/declare/report) is the standard term for intelligence transmission. Sisera responds immediately (v13) by mobilizing all his chariots. The enemy's swift response is not a complication but part of the divine plan: YHWH has drawn (<em>māšak</em>, v7) Sisera to the appointed ground.</p>",
    "13": "<p><em>wayyizʿōq sîsərāʾ ʾet-kol-rikbô</em> — 'Sisera called out all his chariots.' <em>zāʿaq</em> (H2199) — the same muster verb Barak used (v10) — now used of the enemy's mobilization. Nine hundred iron chariots (<em>teša meʾôt rekeb barzel</em>) represent the most sophisticated military technology of the Late Bronze Age. Iron-tipped chariot wheels and reinforced chassis gave Canaanite armies devastating speed and shock power in open terrain. <em>miḥărōšet haggôyim</em> — Harosheth-hagoyim ('forested place of the peoples') was Sisera's base in the Jezreel plain, positioned to control the pass between the plain and the coast.</p>",
    "14": "<p><em>qûm kî zeh hayyôm ʾăšer nātan YHWH ʾet-sîsərāʾ bəyāḏekā</em> — 'Rise, for this is the day on which YHWH has given Sisera into your hand.' The formula <em>nātan bəyāḏ</em> (H5414 H3027, to give into the hand) is the standard commissioning oracle for holy war; its perfect tense in the context of future action is the prophetic perfect — YHWH's deliverance is so certain it is spoken as already accomplished. <em>hălōʾ YHWH yāṣāʾ ləpānêkā</em> — 'Has not YHWH gone out before you?' — YHWH as divine warrior precedes the human army; the battle is YHWH's before it is Barak's.</p>",
    "15": "<p><em>wayyāhom YHWH ʾet-sîsərāʾ</em> — 'YHWH routed (<em>hāmam</em>) Sisera.' <em>hāmam</em> (H2000, to throw into confusion, rout, destroy) is the divine warrior's signature weapon against armies: it was used at the Exodus sea (Exod 14:24 — 'YHWH looked down on the Egyptian army and threw them into confusion'), at Gibeon (Josh 10:10), and here. The verb does not describe what humans did but what YHWH did — 'all his army' fell by the edge of the sword, while Sisera flees on foot. The iron chariotry that made Sisera's force so formidable is rendered useless by divine intervention in the terrain (cf. the Song's reference to the flooding Kishon, 5:21).</p>",
    "16": "<p><em>ûḇārāq rāḏap ʾaḥărê hārekeb wəʾaḥărê heḥāyil ʿaḏ-ḥărōšet haggôyim</em> — 'Barak pursued the chariots and the army to Harosheth-hagoyim.' The pursuit extends to the enemy's home base — a total rout. <em>wayyippōl kol-maḥănēh sîsərāʾ ləpî-ḥereb lōʾ-nišʾar ʿaḏ-ʾeḥāḏ</em> — 'the whole army of Sisera fell by the edge of the sword; not one was left.' The formula <em>lōʾ nišʾar ʿaḏ ʾeḥāḏ</em> (H7604, not one remained) is the language of complete divine judgment — used at the Red Sea (Exod 14:28) and in Joshua's conquests (Josh 10:28-40). The chariot force that had terrorized Israel for twenty years is annihilated in a day.</p>",
    "17": "<p><em>wəsîsərāʾ nās bəraglāyw</em> — 'Sisera fled on foot.' The detail matters: the commander of 900 iron chariots runs on foot — his technology stripped from him. He goes to the tent of Jael (<em>ʾōhel yāʾēl</em>), wife of Heber the Kenite. The Kenites are descendants of Moses's father-in-law Jethro (cf. 1:16), making this a non-Israelite family with covenant loyalty to Israel. The <em>šālôm</em> (H7965, peace) between Jabin and the house of Heber (v17b) explains why Sisera expects safety — a diplomatic status that Jael will override through deeper loyalty.</p>",
    "18": "<p><em>watteṣēʾ yāʾēl liqrāʾt sîsərāʾ wattiʾmer ʾēlāyw sûr ʾăḏōnî sûr ʾēlay ʾal-tîrāʾ</em> — 'Jael went out to meet Sisera and said to him: Turn in, my lord, turn in to me; do not fear.' <em>sûr</em> (H5493, to turn aside/depart from the road) — her invitation is urgent and repeated: turn aside, come in. The threefold hospitality gesture that follows — going out to meet him, inviting him in, covering him — mirrors the host-welcome ritual of the ancient Near East. <em>wayyāsar ʾēlêhā hāʾōhəlāh wattəkasēhû baśśəmîkāh</em> — he turned in to her, into the tent; she covered him with a rug (<em>śəmîkāh</em> H8063, a rug/cover — hapax legomenon). Her hospitality is genuine enough to disarm his suspicion.</p>",
    "19": "<p><em>wayyōʾmer ʾēlêhā hašqînî-nāʾ məʿaṭ-mayim kî ṣāmēʾtî</em> — 'He said to her: Please give me a little water to drink, for I am thirsty.' The narrative is economical and ironic. Sisera asks for water (<em>mayim</em>) — the most basic need. Jael gives him milk (<em>ḥālāḇ</em> H2461, milk/cream — cf. 5:25 where the Song specifies a lordly bowl of curds). <em>ḥēmāt heḥālāḇ</em> (skin of milk/cream) — the nomadic woman's hospitality upgraded: she gives better than was asked. The excess of hospitality deepens his vulnerability and his sleep.</p>",
    "20": "<p><em>wayyōʾmer ʾēlêhā ʿămōḏ petaḥ hāʾōhel wəhāyāh ʾim-ʾîš yāḇōʾ ûšəʾēlēk wəʾāmar hăyēš-pōh ʾîš wəʾāmartə lōʾ</em> — 'He said to her: Stand at the entrance of the tent, and if any man comes and asks you, saying \"Is anyone here?\" say \"No.\"' Sisera attempts to use Jael as his lookout — to make her complicit in his concealment. The irony is complete: the man who commanded nine hundred chariots now places his security in a woman's word. She will speak a word, but not to protect him. The command to deny his presence sets up the narrative reversal — not Sisera but he himself is hiding.</p>",
    "21": "<p><em>wattiqqaḥ yāʾēl ʾēšet-ḥeḇer ʾet-yəṯaḏ hāʾōhel</em> — 'Jael the wife of Heber took the tent peg (<em>yəṯaḏ hāʾōhel</em>).' <em>yāṯēḏ</em> (H3489, tent peg/stake) and <em>hallāmûṯ</em> (H4718, mallet/hammer) are the tools of the nomadic woman's craft — she knows these implements because she is responsible for pitching the tent. Jael uses her domestic competence as a weapon. The Song of Deborah (5:26) elaborates: 'her hand to the tent peg, her right hand to the workmen's mallet.' <em>wayyiṣnaḥ wayyiqqōḇ</em> — she drove it through his temples into the ground (<em>hāʾāreṣ</em>); he was in a deep sleep (<em>nirddam</em>, H7290, to be in deep sleep/stunned) and died.</p>",
    "22": "<p><em>wayyāḇōʾ ḇārāq rōḏēp ʾet-sîsərāʾ</em> — 'And Barak came, pursuing Sisera.' The irony is complete: Barak arrives to find the work done — not by his hand but by Jael's. <em>watteṣēʾ yāʾēl liqrāʾtô wattiʾmer lô lēk wəʾarʾekkā ʾet-hāʾîš ʾăšer ʾattāh məḇaqquēš</em> — 'Jael came out to meet him and said: Come and I will show you the man you are seeking.' She goes out to meet the pursuer just as she went out to meet the fugitive (v18) — the verb <em>yāṣāʾ liqrāʾt</em> frames both encounters. Deborah's prophecy (v9) is now fulfillment: glory has gone to a woman's hand.</p>",
    "23": "<p><em>kēn kānaʿ ʾĕlōhîm bayyôm hahûʾ ʾet yāḇîn melek kənaʿan lipnê bənê yiśrāʾēl</em> — 'Thus on that day God humbled (<em>kānaʿ</em>) Jabin king of Canaan before the sons of Israel.' <em>kānaʿ</em> (H3665, to be brought low, subdued, humbled) is the verb of covenant victory: when Israel is faithful, YHWH subdues their enemies; when Israel apostasizes, Israel itself is subdued. The divine name used here is <em>ʾĕlōhîm</em> (generic God) rather than YHWH — possibly reflecting the narrator's summary perspective, or the universal scope of the victory: the God of all creation, not merely Israel's tribal deity, has done this.</p>",
    "24": "<p><em>wattelek yaḏ bənê yiśrāʾēl hālôk wəqāšāh ʿal yāḇîn melek kənaʿan ʿaḏ ʾăšer hikrîtû ʾet yāḇîn melek kənaʿan</em> — 'The hand of Israel pressed harder and harder against Jabin the king of Canaan, until they had destroyed Jabin king of Canaan.' <em>yāḏ</em> (H3027, hand) — the narrative closes with the political consequence: just as Jabin's <em>yaḏ</em> had oppressed Israel (vv2-3), now Israel's <em>yaḏ</em> presses down on Jabin until destruction. <em>hālôk wəqāšāh</em> (going and growing harsh — an infinitive absolute construction expressing progressive intensification) describes a sustained campaign that ended only with total elimination. Jabin's dynasty that survived Joshua's burning of Hazor (Josh 11:11) is now permanently ended.</p>"
  },
  "5": {
    "1": "<p><em>wattāšar dəḇôrāh ûḇārāq bin-ʾăḇînoʿam bayyôm hahûʾ lēʾmōr</em> — 'Then Deborah and Barak son of Abinoam sang on that day, saying.' The Song of Deborah is one of the oldest extant Hebrew poetic texts, displaying archaic linguistic features (archaic verb forms, rare vocabulary, paratactic syntax) that scholars date to around the 12th century BCE. <em>šîr</em> (H7891, to sing) — victory hymns after deliverance are a consistent pattern: Miriam's Song (Exod 15), the Song of Moses (Deut 32). The dual authorship — Deborah and Barak — reflects their joint role; the Song was evidently her composition performed together.</p>",
    "2": "<p><em>bipraʿ pərāʿôt bəyiśrāʾēl</em> — One of the most debated lines in Judges. <em>pāraʿ</em> (H6544) means 'to let loose, to lead/be free.' The phrase may mean 'When leaders led in Israel' (NRSV, ESV — reading <em>pərāʿôt</em> as a verbal noun for leaders who step up) or 'when men were freely offered/volunteered' (KJV, NASB) or 'when locks of hair were let loose' (reading the Nazirite dedication of warriors as the context). The phrase sets the rhetorical tone: a moment of voluntary, spirited commitment to YHWH's cause. <em>bārûk YHWH</em> — bless YHWH: the Song opens and closes (v31) with YHWH's honor; the victory is his to be praised for.</p>",
    "3": "<p><em>šimʿû məlākîm haʾăzînû rōzənîm ʾānōkî laYHWH ʾānōkî ʾāšîr ʾăzammēr laYHWH ʾĕlōhê yiśrāʾēl</em> — 'Hear, O kings! Give ear, O rulers! I, to YHWH I will sing; I will make music to YHWH, the God of Israel.' The address to kings and rulers as the audience of the victory hymn is a bold theological claim: YHWH's triumph over Sisera is news the kings of the earth must hear. <em>rōzen</em> (H7336, ruler/prince — rare; occurs only 6 times) adds a second tier of leadership to the audience. The double <em>ʾānōkî laYHWH</em> (I, to YHWH) is emphatic dedication: this song is given TO YHWH, not merely about him.</p>",
    "4": "<p><em>YHWH bəṣēʾtkā miśśēʿîr</em> — 'YHWH, when you went out from Seir' — the theophanic march-poem. This strophe (vv4-5) is closely parallel to Deut 33:2 and Ps 68:8-9: YHWH appears marching from the southern wilderness (Seir, Paran, Sinai). The theophanic imagery includes earthquake (<em>rāʿaš</em> H7493, the earth quaked), melting mountains (<em>nāzəlû</em>, the mountains streamed), and storm: <em>ʿāḇîm nāṭāpû mayim</em> — 'the clouds dripped water.' The cosmological scope asserts YHWH as lord of all creation forces, not merely a tribal deity. These archaic theophany poems preserve the oldest Israelite traditions of YHWH's warrior-appearance from the southern mountains.</p>",
    "5": "<p><em>hārîm nāzəlû mippənê YHWH zeh sînay mippənê YHWH ʾĕlōhê yiśrāʾēl</em> — 'The mountains quaked before YHWH, even Sinai before YHWH, the God of Israel.' <em>nāzal</em> (H5140, to flow/drip/stream down) — the mountains do not merely shake but pour forth, a hyperbolic image of cosmic dissolution before the divine march. <em>zeh sînay</em> (this is Sinai / the one of Sinai) is the formulaic identifier appended to YHWH: he is the God whose definitive self-revelation was at Sinai. The Sinai theophany (Exod 19-20) is the template for all subsequent divine appearances — earthquake, fire, and storm. This verse anchors the present victory in the primal covenant-founding event.</p>",
    "6": "<p><em>bîmê šamgar bin-ʿănāt bîmê yāʾēl ḥāḏəlû ʾoraḥôt</em> — 'In the days of Shamgar son of Anath, in the days of Jael, the highways ceased.' <em>ʾōraḥ</em> (H734, road/path) + <em>ḥāḏal</em> (H2308, to cease/stop) describes a state of such insecurity that normal travel has stopped — the sign of complete social breakdown. The reference to <em>pərāzôn</em> (unwalled villages, H6520) in v7 and the absence of shields and spears among 40,000 (v8) confirms an Israel stripped of military capacity. This context makes the victory all the more remarkable: YHWH wins with no conventional army.</p>",
    "7": "<p><em>ḥāḏəlû pərāzôn bəyiśrāʾēl ḥāḏēlû ʿaḏ šaqqamtî dəḇôrāh šaqqamtî ʾēm bəyiśrāʾēl</em> — 'Village life ceased in Israel, it ceased until I, Deborah, arose — I arose as a mother in Israel.' <em>pərāzôn</em> (H6520, open-country villages/rural population) — the unfortified settlements are the vulnerable core of Israel's agrarian life; their cessation means the countryside has been abandoned to the enemy. <em>ʾēm bəyiśrāʾēl</em> (mother in Israel, H517) — the title is unique in the judges narratives; Deborah is not a 'father in Israel' (the male patriarchal title) but a mother — one who nourishes, gathers, protects. The maternal metaphor for covenant leadership anticipates Isa 66:13 ('As one whom his mother comforts, so I will comfort you') and Jesus's lament over Jerusalem (Matt 23:37).</p>",
    "8": "<p><em>yiḇḥar ʾĕlōhîm ḥăḏāšîm ʾāz leḥem šəʿārîm māgēn wəʾim-yērāʾeh wārōmaḥ bəʾarbaʿîm ʾelep bəyiśrāʾēl</em> — 'They chose new gods; then war was in the gates. Was a shield or spear seen among 40,000 in Israel?' The verse is among the most debated in the Song for its syntax and referent: the 'they' who chose new gods is Israel, and the consequence was war at the gates (the enemy was inside the defensive perimeter). The military disarmament — no shield (<em>māgēn</em> H4043) or spear (<em>rōmaḥ</em> H7420) among forty thousand — is the result of idolatry. When Israel abandons YHWH, YHWH allows the removal of the means of self-defense. The victory that follows will be unmistakably divine.</p>",
    "9": "<p><em>libbî ləḥôqəqê yiśrāʾēl hammitnaḏḏəḇîm bāʿām bārăkû YHWH</em> — 'My heart is with the commanders (<em>ḥōqēq</em>) of Israel who offered themselves willingly (<em>nāḏaḇ</em>) among the people — bless YHWH.' <em>ḥōqēq</em> (H2710, one who inscribes/decrees/commands — from the root of engraving the law; used of the lawgiver's scepter in Gen 49:10 and Num 21:18) — the word elevates the tribal commanders to quasi-legislative status: they are those who decree and lead. <em>hitnaddēḇ</em> (H5068, to volunteer/offer oneself freely) is the key virtue celebrated in the Song: the willing offering of oneself in response to covenant crisis, parallel to the freewill offerings of the tabernacle (Exod 35:21-29).</p>",
    "10": "<p><em>rōḵəḇê ʾătōnôt ṣəḥōrôt yōšəḇê ʿal-miḏîn wəhōlăkê ʿal-dereḵ śîḥû</em> — 'You who ride on tawny donkeys, you who sit on rich carpets, and you who walk by the road — consider!' <em>ʾătōn ṣəḥōrāh</em> (H860, H6715 — tawny/white she-donkey) is the mount of dignity in the ancient Near East (cf. Judg 10:4; 12:14 — sons who rode on seventy donkeys; Zech 9:9 — the king comes on a donkey). The triad — riders of distinction, those at ease, travelers on the road — represents all of Israelite society being summoned to attend and recount the victory. <em>śîḥû</em> (H7878, to muse/meditate/speak) — the root suggests both inner meditation and outward declaration of YHWH's acts.</p>",
    "11": "<p><em>məqôl məḥaṣṣəṣîm bên mašʾabbôt šam yəṯannû ṣiḏqôt YHWH ṣiḏqōt pirzonô bəyiśrāʾēl</em> — 'At the sound of those who divide flocks among the watering places, there they rehearse the righteous acts of YHWH, the righteous acts of his village warriors in Israel.' <em>ṣiḏqāh</em> (H6666, righteousness/righteous act/victory) — the 'righteous acts of YHWH' is a rich phrase: it encompasses both YHWH's covenant faithfulness and his saving interventions. The setting — watering holes where shepherds gather — suggests the victory story is transmitted in communal oral recitation. <em>pārazon</em>/<em>pārāzî</em> (v7, H6520/H6521, village-dwellers/open-land warriors) are the free farmers who volunteered, contrasting with professional armies.</p>",
    "12": "<p><em>ʿûrî ʿûrî dəḇôrāh ʿûrî ʿûrî daббərî-šîr qûm bārāq ûšəḇeh šiḇyəkā bin-ʾăḇînoʿam</em> — 'Awake, awake, Deborah! Awake, awake, strike up a song! Rise up, Barak, and lead away your captives, son of Abinoam.' The fourfold <em>ʿûrî</em> (H5782, awake!/rouse yourself!) is a battle cry and a summons to prophetic speech — the same root that opens the Servant's ear in Isa 50:4 ('He awakens my ear morning by morning'). The double imperative — awake to song, rise to captives — links prophetic proclamation with military reality. <em>šəḇeh šiḇyəkā</em> (H7617/H7628, lead away your captives) is the language of post-battle spoil-taking, used of YHWH's own cosmic victories (Ps 68:18).</p>",
    "13": "<p><em>ʾāz yāraḏ śārîṭ laʾaddîrîm ʿam YHWH yāraḏ lî baggibborîm</em> — 'Then down marched the remnant of the noble; the people of YHWH marched down for me among the mighty.' <em>śārîṭ</em> is textually uncertain (some read <em>śārîd</em> H8300, survivor/remnant); the meaning is those who remain/the remnant who stepped up. <em>ʾaddîr</em> (H117, noble/mighty — used of YHWH's own majesty in Ps 8:1) applied to the volunteers exalts the tribal warriors to a regal dignity. <em>ʿam YHWH</em> (people of YHWH) — the designation that marks the fighters as covenant participants, not merely tribal levies. Their descent into battle is YHWH's own descent.</p>",
    "14": "<p><em>minnî ʾeprayim šārāšām bāʿămālēq ʾaḥărêkā ḇinyāmîn bəʿămmêkā</em> — 'From Ephraim their root was in Amalek; after you, Benjamin, with your clans.' The tribal roll call of participation/non-participation is the Song's sharpest rhetorical device: praise for those who came, oblique rebuke for those who did not. Ephraim's root 'in Amalek' is enigmatic — possibly referring to a region called Amalek within Ephraim's territory (cf. 12:15, 'the hill country of the Amalekites'). Benjamin 'after you' places the southern tribe behind Ephraim in the march order. Machir (representing Manasseh) and Zebulun follow — tribal volunteers honored by name in the divine record.</p>",
    "15": "<p><em>wəśārāyw byiśśāśkār ʿim-dəḇôrāh wəyiśśāśkār kēn ḇārāq bāʿēmeq šullaḥ bəraglāyw</em> — 'The commanders of Issachar came with Deborah; and Issachar — so faithful to Barak; into the valley they rushed at his feet.' <em>šālaḥ bəraglāyw</em> (sent/rushed at his feet — idiom for following energetically) — Issachar's loyalty is marked by the pun: they rushed at Barak's feet (<em>raglāyw</em>) just as the troops followed Barak 'at his feet' (v10). <em>bip̄laggôt rəʾûḇēn gədôlîm ḥiqqê-lēḇ</em> — 'Among the clans of Reuben there were great searchings of heart' — the first note of rebuke; Reuben deliberated but did not come.</p>",
    "16": "<p><em>lāmmāh yāšaḇtā bên hammišpətāyim lišmōaʿ šəriqôt ʿăḏārîm</em> — 'Why did you sit among the sheepfolds, listening to the piping for the flocks?' The question directed at Reuben is rhetorical and devastating: while the battle raged, Reuben stayed home to tend sheep. <em>mišpetayim</em> (H4942, sheepfolds/saddlebags — dual form, possibly meaning the two folds) and <em>šərîqôt ʿăḏārîm</em> (the piping/whistling for the flocks — the shepherd's call) paint a picture of pastoral complacency while covenant brothers fought for survival. <em>lipəlaggôt rəʾûḇēn gədôlîm ḥiqqrê-lēḇ</em> — 'Among the clans of Reuben there were great searchings (<em>ḥeqer</em> H2714, deep searchings/investigations) of heart (<em>lēḇ</em>)' — not courage but indecision, the deep deliberation that leads to inaction.</p>",
    "17": "<p><em>gilʿāḏ bəʿēḇer hayyardēn šākān wəḏān lāmmāh yāgûr ʾŏniyyôt ʾāšēr yāšaḇ ləḥôp hayyammîm ûʿal mipərāṣāyw yiškôn</em> — 'Gilead stayed beyond the Jordan; Dan, why did he stay beside the ships? Asher sat still at the coast of the sea, settling beside his inlets.' Gilead (Gad + half-Manasseh east of Jordan), Dan, and Asher are rebuked for geographic/economic calculations overriding covenant solidarity. Dan's association with ships (<em>ʾŏniyyôt</em> H591) implies a maritime trade connection — possibly Dan had settled in coastal areas where commercial interests trumped military ones. Asher's sitting at the sea-coast (<em>ḥôp hayyām</em>) confirms a similar maritime orientation. The contrast with Zebulun and Naphtali (v18) is total.</p>",
    "18": "<p><em>zəḇûlun ʿam ḥērēp napšô lāmût wənaptālî ʿal mərômê śāḏeh</em> — 'Zebulun is a people who risked their lives to the point of death; Naphtali also, on the heights of the field.' <em>ḥārap</em> (H2778, to reproach/defy/expose to contempt — here used in the sense of despising one's own life, giving it away) — Zebulun 'reproached' or 'exposed' their lives to death (<em>lāmût</em>). The idiom means they staked their lives recklessly. Naphtali on the 'heights of the field' (<em>mərômê śāḏeh</em>) stood exposed on the high ground — the position of maximum visibility and maximum vulnerability. The willingness to die for YHWH's cause is the Song's highest honor.</p>",
    "19": "<p><em>bāʾû məlākîm nilḥāmû ʾāz nilḥəmû malkê kənaʿan bətaʿnak ʿal-mê məgiddô beṣaʿ kesef lōʾ lāqāḥû</em> — 'Kings came, they fought; then the kings of Canaan fought at Taanach by the waters of Megiddo; they took no plunder of silver.' The battle is elevated to a royal-level conflict — the Canaanite coalition represents the full weight of regional power. Taanach and Megiddo are the two great fortress cities flanking the Jezreel Valley's narrowest point, the strategic chokehold of the region. <em>beṣaʿ kesef lōʾ lāqāḥû</em> — 'no plunder of silver did they take' — the expected outcome of victory (plunder) was reversed: the intended plunderers (the kings) took nothing, because YHWH routed them before they could collect.</p>",
    "20": "<p><em>min-šāmayim nilḥāmû hakkôkāḇîm mimməsilôtām nilḥāmû ʿim-sîsərāʾ</em> — 'From heaven the stars fought, from their courses they fought against Sisera.' Stars as divine warriors fighting on YHWH's behalf is ancient cosmological language: the heavenly host (H6635 <em>ṣāḇāʾ</em>) is YHWH's army, and its deployment against Sisera means all of creation is arrayed against him. The verse may also encode meteorological reality — the heavenly disruption (storm, flooding of the Kishon, v21) that made the iron chariots useless. <em>məsillāh</em> (H4546, course/highway — their ordained paths) — the stars fight from their divinely appointed courses, implying cosmic order weaponized against the enemies of covenant.</p>",
    "21": "<p><em>naḥal qîšôn gərāpām naḥal qədûmîm naḥal qîšôn</em> — 'The Kishon swept them away, the ancient river, the Kishon river.' <em>qîšôn</em> (H7028) is the river draining the Jezreel Valley toward the sea. <em>gārap</em> (H1640, to sweep away — only here and Ps 40:3) describes a flash flood sweeping things away. <em>qəḏûmîm</em> (ancient/primeval, H6924) gives the river an age-old character — the Kishon has always been the place of divine victory. The flooding of the Kishon is the natural mechanism by which YHWH's battle began: iron chariot wheels mired in mud become a trap rather than an asset.</p>",
    "22": "<p><em>ʾāz hālamû ʿiqqəḇê-sûs midahărôt daharôt ʾabbîrāyw</em> — 'Then loud beat the horses' hoofs with the galloping, galloping of his chargers.' <em>dāhar</em> (H1725, to gallop — onomatopoetic; the doubling <em>daharôt daharôt</em> mimics the drumming of hoofs) captures the sound of the routing cavalry. <em>ʿiqqēḇ</em> (H6119, heel/footprint/hoof-beat) — the stamping hoofs of panicking horses encode the terror of the routed army. The phonetic texture of this verse — alliterative, percussive — is among the finest examples of archaic Hebrew sound-poetry, imitating the very battle sounds it describes.</p>",
    "23": "<p><em>ʾôrû mērôz ʾāmar malʾak YHWH ʾôrû ʾārôr yōšəḇêhā kî lōʾ-ḇāʾû ləʿezrat YHWH ləʿezrat YHWH baggibborîm</em> — 'Curse Meroz, says the angel of YHWH, curse its inhabitants bitterly, because they did not come to the help of YHWH, to the help of YHWH against the mighty.' <em>ārûr</em> (H779, curse — the covenant curse, the opposite of <em>bārûk</em>) pronounced through the divine messenger is the strongest possible negative. Meroz is the only place cursed by name; its location is unknown, which has led some to see it as a deliberate mystery — any community that refuses YHWH's call is Meroz. <em>ʿezrat YHWH</em> — 'to the help of YHWH' — a striking reversal: YHWH does not need human help, but covenant participation in YHWH's battle is how faithfulness is demonstrated.</p>",
    "24": "<p><em>təḇōrak minnāšîm yāʾēl ʾēšet ḥeḇer haqqênî minnāšîm bāʾōhel təḇōrāk</em> — 'Most blessed of women be Jael, the wife of Heber the Kenite — of tent-dwelling women most blessed.' <em>bārak</em> (H1288, to bless) in the Piel — the intensive blessing formula reserved for those who act decisively for YHWH's cause. 'Most blessed of women' (<em>minnāšîm</em> — the comparative partitive: more blessed than all women) anticipates the same formula used of Mary in Luke 1:42 ('Blessed are you among women'). Both Jael and Mary are women through whom the decisive blow against the enemy comes — Jael with the tent peg, Mary by bearing the one who would crush the serpent's head.</p>",
    "25": "<p><em>mayim šāʾal ḥālāḇ nāṯānāh bəsēpel ʾaddîrîm hiqrîḇāh ḥemʾāh</em> — 'He asked for water, she gave him milk; in a lordly bowl she brought him curds (<em>ḥemʾāh</em>).' <em>ḥemʾāh</em> (H2529, cream/curds/butter — the best of milk products) in a <em>sēpel ʾaddîrîm</em> (H5602 H117, a basin of nobles/magnificent bowl) — she treated him like a honored guest. The irony is pointed: the finest hospitality — better than he asked for, served in a royal vessel — precedes his death. The Song's version of the killing (vv26-27) is more elaborate than the prose account, showing Jael as a skilled warrior rather than an opportunistic killer.</p>",
    "26": "<p><em>yāḏāh layyāṯēḏ tišlaḥnāh wîmînāh ləhalmût ʿămēlîm</em> — 'Her hand she sent to the tent peg, her right hand to the workmen's mallet.' <em>yāṯēḏ</em> (H3489, tent peg) and <em>halmût</em> (H1989, mallet — related to <em>hāmam</em> to strike/shatter) — the domestic tools recast as weapons. The Song's slow, deliberate enumeration — hand to peg, right hand to mallet, she hammered, she struck, she pierced — is designed to make the audience dwell on each action. <em>wəhālaməṯāh sîsərāʾ māḥăqāh rōʾšô ûmāḥăṣāh wəḥālǝpāh raqqātô</em> — she hammered Sisera, she crushed his head, she shattered and pierced his temple. The verbs pile up: <em>māḥaq</em> (H4272, to shatter), <em>māḥaṣ</em> (H4272, to smite/wound through), <em>ḥālap</em> (H2498, to pierce through).</p>",
    "27": "<p><em>bên raglêhā kāraʿ nāpal šāḵaḇ bên raglêhā kāraʿ nāpal baʾăšer kāraʿ šām nāpal šāḏûḏ</em> — 'Between her feet he sank, he fell, he lay; between her feet he sank, he fell; where he sank, there he fell — destroyed.' The triple repetition (<em>kāraʿ nāpal</em> — sank, fell) is the Song's triumphant cadence over the dead commander. <em>šāḏûḏ</em> (H7703, destroyed/devastated) — the final word tolls like a bell. The three-beat descent — sank, fell, lay still — may deliberately mirror the fall of an idol: the great and feared becomes prostrate before a woman of God. Ps 20:8 uses the same verbs: 'They collapse and fall, but we rise and stand upright.'</p>",
    "28": "<p><em>bəʿaḏ hallôn nišqǝpāh wattəyabbēb ʾēm sîsərāʾ bəʿaḏ hāʾešnāb</em> — 'Out of the window she peered, the mother of Sisera wailed through the lattice.' The scene shifts to Sisera's home — his mother watching and waiting. <em>nišqǝpāh</em> (H8259, to peer/look out) and <em>yābab</em> (H2980, to wail/cry out) paint the waiting woman's grief beginning even before she knows the outcome. The window-and-lattice scene (<em>ʾešnāb</em> H822, a latticed window) is an image from Canaanite iconography — the 'woman in the window' is a motif found on carved ivories from Megiddo and other sites, depicting a noble woman watching for a lover's return. Here the beloved does not return.</p>",
    "29": "<p><em>ḥakəmôt śārôtêhā taʿānenāh ʾap-hîʾ tāšîḇ ʾămārêhā lāh</em> — 'Her wisest princesses answer; indeed, she herself answers her own words.' <em>ḥāḵām</em> (H2450, wise) — the 'wise ladies' (feminine plural) are the court women who construct reassuring interpretations of the delay. The phrase <em>ʾap-hîʾ tāšîḇ ʾămārêhā</em> — 'she even answers her own words back to herself' — shows Sisera's mother generating her own comfort rather than receiving it. She speaks in order to silence her own dread. The irony of the wise women's counsel (v30) is that they construct a fiction of victory precisely when the reverse has occurred.</p>",
    "30": "<p><em>hălōʾ yimṣəʾû yəḥallèqû šālāl raḥam raḥămātayim ləraʾš gāḇer</em> — 'Are they not finding and dividing the spoil? A womb or two for every warrior?' The mother's reassuring reconstruction is brutal in its candor: <em>raḥam</em> (H7358, womb — by metonymy, a woman as sexual prize) is the expected spoil of conquest. The Song does not soften this: Sisera's victory would have meant the rape of Israelite women. By naming it plainly, Deborah's Song pronounces judgment on the Canaanite war-economy that commodified women as plunder. The victory that prevented this is thus not merely military but moral — YHWH protected what Sisera would have violated.</p>",
    "31": "<p><em>kēn yōḇdû kol-ʾōyəḇêkā YHWH wəʾōhăḇāyw kəṣēʾt haššemeš bigbûrātô</em> — 'So shall all your enemies perish, O YHWH! But let those who love him be like the sun as it rises in its might.' The Song's closing benediction is structured as an antithetic parallelism: the fate of YHWH's enemies (perishing) vs. the fate of his lovers (radiant ascent). <em>gəḇûrāh</em> (H1369, might/strength/valor) applied to the rising sun is a striking metaphor: the sun at dawn rises with growing force, unchallenged. <em>ʾōhăḇāyw</em> (those who love him, H157) — covenant love language; in Deut 6:5 Israel is commanded to love YHWH with all their heart, soul, and strength. The covenant lovers will match the solar glorification at the end of history (cf. Matt 13:43 — 'the righteous will shine like the sun in the kingdom of their Father').</p>"
  },
  "6": {
    "1": "<p><em>wayyaʿăśû bənê yiśrāʾēl hāraʿ bəʿênê YHWH wayyittənēm YHWH bəyaḏ-miḏyān šeḇaʿ šānîm</em> — 'The sons of Israel did the evil in the eyes of YHWH, and YHWH gave them into the hand of Midian seven years.' The cycle formula now has seven years of oppression — the number seven intensifies the judgment. Midian (<em>miḏyān</em>) was Israel's ancestral ally (Jethro/Reuel was Moses's father-in-law) turned adversary; the oppression is thus a family betrayal as well as a theological judgment. The repetition of <em>nātan bəyāḏ</em> (H5414 H3027 — gave into the hand) shows YHWH as the active agent of punishment, not merely the passive permitter.</p>",
    "2": "<p><em>watteʿaz yaḏ-miḏyān ʿal-yiśrāʾēl mippənê miḏyān ʿāśû lāhem bənê yiśrāʾēl ʾet-hamminharôt ʾăšer behehārîm wəʾet-hamməʿārôt wəʾet-hammǝṣāḏôt</em> — 'The hand of Midian overpowered Israel, and because of Midian the sons of Israel made themselves the dens in the mountains and the caves and the strongholds.' <em>ʿāzaz</em> (H5810, to be strong/prevail) in the Qal describes Midian's military dominance as a physical weight pressing down on Israel. The three hiding places — <em>minharôt</em> (clefts/shafts H4492), <em>məʿārôt</em> (caves H4631), <em>məṣāḏôt</em> (strongholds H4679) — describe the progressive retreat of a society from its land into the earth itself. The agrarian people have become cave-dwellers: a complete reversal of the Exodus gift of a land flowing with milk and honey.</p>",
    "3": "<p><em>wəhāyāh ʾim-zāraʿ yiśrāʾēl wəʿālāh miḏyān wəʿămālēq ûḇənê-qeḏem wəʿālû ʿālāyw</em> — 'Whenever Israel planted, Midian and Amalek and the people of the East would come up against them.' <em>zāraʿ</em> (H2232, to sow/plant) is the fundamental act of settled agrarian life; the moment of planting triggers the Midianite raid. The three-part coalition — Midian, Amalek, and the people of the East — describes a pan-desert alliance of pastoral/nomadic peoples preying systematically on Israel's agricultural surplus. The timing is deliberate: they do not prevent planting but destroy the harvest, maximizing Israel's labor and their own gain.</p>",
    "4": "<p><em>wayyaḥănû ʿălêhem wayyašḥîtû ʾet-yəḇûl hāʾāreṣ ʿaḏ-bōʾăkā ʿazzāh wəlōʾ-yišʾîrû mihyāh bəyiśrāʾēl wəlōʾ-śeh wəlōʾ-šôr wəlōʾ-ḥamôr</em> — 'They would encamp against Israel and destroy the produce of the land as far as Gaza, and leave no sustenance for Israel, and no sheep or ox or donkey.' <em>šāḥat</em> (H7843, to destroy/corrupt/ruin) — the verb used of the Flood (Gen 6:12) and Sodom (Gen 19:13); the Midianite destruction of crops is described in the most extreme terms. The enumeration of no sheep, no ox, no donkey is the destruction of the entire domestic economy. Israel is being systematically stripped of its covenant inheritance.</p>",
    "5": "<p><em>kî hem ûmiqdnêhem yaʿălû ûʾohŏlêhem kāʾarḇeh lārōḇ ûlāhem ûligmallêhem ʾên mispar</em> — 'For they and their livestock would come up with their tents, coming like locusts for number; and they and their camels were without number.' <em>ʾarḇeh</em> (H697, locust — the great plague insect of Exod 10) — the locust comparison is the most devastating available in Hebrew rhetoric: a swarm that consumes everything and cannot be stopped by conventional means. The emphasis on the innumerability of camels is historically significant: the Midianite raids represent the first recorded large-scale military use of camels in the ancient Near East, a new technology of desert mobility that gave raiders a reach no foot-army could counter.</p>",
    "6": "<p><em>wayyiddal yiśrāʾēl məʾōd mippənê miḏyān</em> — 'Israel was made very weak/low by reason of Midian.' <em>dālal</em> (H1809, to dangle/hang low, to be brought low — used of exhausted, depleted persons) captures the totality of the decline: Israel has been reduced to hiding in mountain caves (v2), and the Midianites swarm the land like locusts (<em>ʾarḇeh</em> H697, v5) consuming everything. <em>wayyiṣʿaqû bənê-yiśrāʾēl ʾel-YHWH</em> — Israel's cry to YHWH here is preceded by the divine response of a prophet (vv7-10) who diagnoses the problem before YHWH sends the deliverer. The prophetic word precedes the gift of a judge — the standard means of grace is the word.</p>",
    "7": "<p><em>wayhî kî-ṣāʿaqû bənê-yiśrāʾēl ʾel-YHWH ʿal-ʾōḏôt miḏyān</em> — 'When the sons of Israel cried out to YHWH on account of Midian, YHWH sent a prophet to them.' The sequence — Israel cries out, YHWH responds — is the judge cycle's heartbeat. But here, instead of sending a judge, YHWH first sends a prophet. <em>šālaḥ nāḇîʾ</em> (H7971 H5030, sent a prophet) — the unnamed prophet (vv8-10) is unique in Judges: an anonymous prophetic voice that delivers a covenant lawsuit before the theophanic commissioning of Gideon. The word must precede the deliverer: diagnosis before remedy.</p>",
    "8": "<p><em>wayyōʾmer lāhem kōh-ʾāmar YHWH ʾĕlōhê yiśrāʾēl ʾānōkî heʿēlêtî ʾetkem mimmiṣrayim</em> — 'He said to them: Thus says YHWH the God of Israel: I brought you up from Egypt.' <em>kōh ʾāmar YHWH</em> — 'Thus says YHWH' — the prophetic messenger formula; the anonymous prophet speaks with full prophetic authority. The content is a recitation of the saving history: Exodus from Egypt, deliverance from all who oppressed (v9), gift of the land. The historical recitation is the covenant lawsuit's first act — establishing what YHWH has done, which makes Israel's apostasy inexcusable. <em>miyyaḏ kol-lōḥăṣêkem</em> (from the hand of all your oppressors) — the summary of covenant protection history.</p>",
    "9": "<p><em>waʾăṣîl ʾetkem miyyaḏ miṣrayim ûmiyyaḏ kol-lōḥăṣêkem wāʾăgārēš ʾôtām mippənêkem wāʾettənāh lākem ʾet-ʾarṣām</em> — 'I delivered you from the hand of Egypt and from the hand of all who oppressed you; I drove them out before you and gave you their land.' Three sovereign acts: <em>nāṣal</em> (H5337, to deliver/rescue from), <em>gāraš</em> (H1644, to drive out/expel), <em>nātan</em> (H5414, to give). The succession of divine first-person verbs is the covenant-establishing narrative in miniature: rescue, dispossession of enemies, gift of land. The land now being ravaged by Midian was given by YHWH — its violation is thus a theological insult to the Giver.</p>",
    "10": "<p><em>wāʾōmar lākem ʾănî YHWH ʾĕlōhêkem lōʾ tîrəʾû ʾet-ʾĕlōhê hāʾĕmōrî ʾăšer ʾattem yôšəḇîm bəʾarṣām wəlōʾ šəmaʿtem bəqôlî</em> — 'I said to you: I am YHWH your God; you shall not fear the gods of the Amorites in whose land you dwell. But you have not obeyed my voice.' The covenant charge is delivered with the first commandment formula: <em>ʾănî YHWH ʾĕlōhêkem</em> — 'I am YHWH your God' (Exod 20:2). The prohibition is against fearing (<em>yārēʾ</em> H3372 — the term encompasses both religious reverence and practical submission) the gods of the Amorites. <em>wəlōʾ šəmaʿtem bəqôlî</em> — 'but you have not obeyed my voice' — the covenant indictment in two Hebrew words. No further rebuke is given; the prophet states the case and stops. YHWH's grace is that he then sends a deliverer anyway.</p>",
    "11": "<p><em>wayyāḇōʾ malʾak YHWH wayyēšeḇ taḥat hāʾēlāh ʾăšer biʿoprāh</em> — 'The angel of YHWH came and sat under the oak that was at Ophrah.' <em>malʾak YHWH</em> (H4397 H3068, messenger/angel of YHWH) — in the patriarchal and early period narratives, the <em>malʾak YHWH</em> is a figure who speaks as YHWH in the first person, is identified with YHWH (v14: 'YHWH looked at him'), yet is distinguishable from him. <em>wayyāšaḇ</em> (H3427, sat/dwelt) — the angel's posture is that of one settling in to wait, not passing through. <em>ʾēlāh</em> (H424, terebinth/oak) is the sacred tree type under which theophanies and divine encounters often occur (cf. Gen 12:6; Judg 4:11).</p>",
    "12": "<p><em>wayyērāʾ ʾēlāyw malʾak YHWH wayyōʾmer ʾēlāyw YHWH ʿimmāk gibbôr heḥāyil</em> — 'The angel of YHWH appeared to him and said to him: YHWH is with you, O mighty warrior.' The greeting <em>YHWH ʿimmāk</em> (H3068 H5973 = YHWH is with you) is the covenant presence formula — the same used with Isaac (Gen 26:24), Moses (Exod 3:12), Joshua (Josh 1:5), and later with the virgin Mary (Luke 1:28 — <em>kúrios metà soû</em>). <em>gibbôr heḥāyil</em> (H1368 H2428, mighty man of valor/warrior of strength) — addressed to a man threshing wheat in secret to hide it from Midian — is not a description of Gideon's present state but a declaration of what YHWH sees and is calling him to be. Divine calling names a destiny, not a present reality.</p>",
    "13": "<p><em>wayyōʾmer ʾēlāyw giḏʿôn bî ʾăḏōnî</em> — 'Gideon said to him: Please, my lord...' Gideon's response is a theodicy question: if YHWH is with us, why has all this happened? <em>ʾayyēh kol-nipləʾōṯāyw</em> — 'where are all his wonderful deeds?' <em>niplāʾôt</em> (H6381 root, wonders/miracles) — Gideon appeals to the Exodus tradition: the fathers told us YHWH brought us up from Egypt. The contrast between past miracle and present disaster is the classic lament structure: we remember your acts of old, but now you have abandoned us. The question is honest and is not rebuked — YHWH answers it not with explanation but with commissioning.</p>",
    "14": "<p><em>wayyipeŋ ʾēlāyw YHWH wayyōʾmer lēk bəkōḥăkā zeh wəhôšaʿtā ʾet-yiśrāʾēl</em> — 'YHWH turned to him and said: Go in this might of yours and save Israel.' <em>pānāh ʾēl</em> (H6437, to turn/face toward) — YHWH turns attention directly to Gideon, a gesture of focused divine address. The phrase <em>bəkōḥăkā zeh</em> (in this your might/strength) is ironic given Gideon's expressed weakness — but 'this' may refer to the audacity of his theodicy question, which is itself a form of faith: you know the exodus tradition and you are holding YHWH to it. <em>hălōʾ šəlaḥtîkā</em> — 'Have I not sent you?' — the commissioning formula that echoes Moses in Exod 3:12.</p>",
    "15": "<p><em>wayyōʾmer ʾēlāyw bî ʾăḏōnî bammāh ʾôšîaʿ ʾet-yiśrāʾēl hinnēh ʾalpî haddal bimənašše wəʾānōkî haqqāṭōn bəḇêt ʾāḇî</em> — 'He said to him: Please, my lord, how shall I save Israel? Behold, my clan is the weakest (<em>haddal</em>) in Manasseh, and I am the least (<em>haqqāṭōn</em>) in my father's house.' <em>dallāh</em>/haddal (H1800/1803, the weak/lowly/thin/impoverished one) and <em>qāṭōn</em> (H6996, small/least/youngest) frame Gideon's objection in terms of social insignificance. The double diminutive — weakest tribe, youngest in family — establishes the principle that YHWH's deliverer will carry no natural advantage. Compare Moses's objections (Exod 4:10), Jeremiah's (Jer 1:6), and Paul's (1 Cor 2:3).</p>",
    "16": "<p><em>wayyōʾmer ʾēlāyw YHWH kî ʾehyeh ʿimmāk wəhikkîtā ʾet-miḏyān kəʾîš ʾeḥāḏ</em> — 'YHWH said to him: But I will be with you, and you shall strike Midian as one man.' <em>kî ʾehyeh ʿimmāk</em> — the divine answer to human inadequacy is always the same: 'I will be with you' (<em>ʾehyeh</em> = H1961, the imperfect of <em>hāyāh</em> to be, related to the divine name YHWH revealed in Exod 3:14). The commissioning formula here exactly matches Exod 3:12: God's answer to Moses's 'Who am I?' was 'I will be with you' — not a credential for Moses but a promise of divine presence. The victory will be so complete that Midian will fall 'as one man' (<em>kəʾîš ʾeḥāḏ</em>) — a singular unified defeat.</p>",
    "17": "<p><em>wayyōʾmer ʾēlāyw ʾim-nāʾ māṣāʾtî ḥēn bəʿênêkā wəʿāśîtā lî ʾôt ʾattāh mədabbēr ʿimmî</em> — 'He said to him: If I have found favor in your eyes, give me a sign that it is you who speaks with me.' <em>māṣāʾ ḥēn bəʿênê</em> (H4672 H2580 H5869, to find grace/favor in the eyes of) — the covenant petition formula, used by Moses before YHWH (Exod 33:13, 16) and by Gideon here. The request for a sign (<em>ʾôt</em> H226) is not unbelief but the prophetic/covenantal procedure for verification: Gideon is following the Deuteronomic principle (Deut 18:21-22) that a prophet's word requires confirmation. The sign requested is not a cosmic event but a personal demonstration: remain here while I prepare an offering.</p>",
    "18": "<p><em>ʾal-nāʾ tāmûš mizzeh ʿaḏ-bōʾî ʾēlêkā wəhôṣēʾtî ʾet-minḥātî wəhinnáḥtî ləpānêkā</em> — 'Please do not depart from here until I come to you and bring out my offering and set it before you.' <em>sûr</em>/<em>mûš</em> (H4185, to depart/move away) — Gideon's plea that the angel not leave echoes the covenant petition for divine presence; without the angel's continued presence, the sign cannot be given. <em>minḥāh</em> (H4503, offering/gift — the grain offering, but here a hospitality gift that becomes a sacrificial offering) — Gideon prepares what will become the content of the sign. The angel's 'I will wait until you return' (<em>ʾēšēb ʿaḏ-šûḇekā</em>) is the divine patience with human hesitation.</p>",
    "19": "<p><em>wəgiḏʿôn bāʾ wayaʿaś gəḏî-ʿizzîm wəʾêpāh qemeaḥ maṣṣôt</em> — 'Gideon went in and prepared a young goat and unleavened cakes from an ephah of flour.' The offering is substantial: a young goat (<em>gəḏî ʿizzîm</em> H1423 H5795) and an entire ephah (approximately 22 liters) of flour made into unleavened cakes (<em>maṣṣôt</em> H4682 — the same bread of the Passover/Exodus). <em>maṣṣôt</em> is not merely economical (it can be prepared quickly) but theologically freighted: unleavened bread is the bread of hasty divine action. Gideon's offering takes on the character of a Passover meal — and the angel's fire will consume it as an altar-sacrifice.</p>",
    "20": "<p><em>wayyōʾmer ʾēlāyw malʾak hāʾĕlōhîm qaḥ ʾet-habbāśār wəʾet-hammaṣṣôt wəhannáḥ ʾel-hassellaʿ hazzeh wəhašpôk ʾet-hammārāq</em> — 'The angel of God said to him: Take the meat and the unleavened cakes, and put them on this rock, and pour the broth over them.' The rock (<em>sellaʿ</em> H5553, a large crag/boulder) becomes the altar; the angel's instruction converts hospitality into sacrifice. <em>wayyaʿaś kēn</em> — he did so. The angel's redirection of the meal from table to rock is the pivotal moment: the guest is revealed as the host of a divine encounter, not the recipient of human hospitality.</p>",
    "21": "<p><em>wayyišlaḥ malʾak YHWH ʾet-qəṣēh hammišʿenet ʾăšer bəyāḏô wayyigaʿ baббāśār ûḇammaṣṣôt wayyaʿal hāʾēš min-hassellaʿ wattiʾkal ʾet-habbāśār wəʾet-hammaṣṣôt ûmalʾak YHWH hālak mēʿênāyw</em> — 'The angel of YHWH reached out the tip of the staff that was in his hand and touched the meat and the unleavened cakes. Fire sprang up from the rock and consumed the meat and the unleavened cakes. And the angel of YHWH vanished from his sight.' The fire from the rock consuming the offering is the theophanic fire-sign: the same pattern as Elijah's altar on Carmel (1 Kgs 18:38 — 'fire of YHWH fell and consumed'), Manoah's offering (13:20 — 'the flame went up toward heaven from the altar'). The immediate disappearance of the angel completes the revelation: this was no human messenger but the divine presence itself.</p>",
    "22": "<p><em>wayyarʾ giḏʿôn kî-malʾak YHWH hûʾ</em> — 'Gideon saw that he was the angel of YHWH.' Only after the offering is consumed by fire and the angel vanishes does Gideon recognize what he had been speaking to. <em>wayyōʾmer ʾahāh ʾăḏōnāy YHWH kî-ʿal-kēn rāʾîtî malʾak YHWH pānîm ʾel-pānîm</em> — 'He said: Alas, Lord YHWH! For I have seen the angel of YHWH face to face!' <em>pānîm ʾel-pānîm</em> (H6440, face to face) — the same idiom as Moses and YHWH (Exod 33:11; Deut 34:10). The terror is that seeing YHWH's face brings death (Exod 33:20; Gen 32:30 — Jacob 'I have seen God face to face and yet my life was delivered').</p>",
    "23": "<p><em>wayyōʾmer lô YHWH šālôm lāk ʾal-tîrāʾ lōʾ tāmût</em> — 'YHWH said to him: Peace be to you. Do not fear; you will not die.' The divine word counters the panic with <em>šālôm</em> (H7965, peace/wholeness/well-being). This direct divine assurance — 'you will not die' — is not merely comfort but promise: Gideon's mission is not yet complete. The assurance becomes the content of the altar name.</p>",
    "24": "<p><em>wayyiḇen šām giḏʿôn mizbēaḥ laYHWH wayyiqrāʾ-lô YHWH šālôm</em> — 'Gideon built an altar there to YHWH and called it YHWH-Shalom.' <em>mizbēaḥ</em> (H4196, altar — from <em>zāḇaḥ</em> to slaughter/sacrifice) built at a theophany site is a patriarchal pattern (Abraham, Gen 12:7-8; Jacob, Gen 33:20). The altar name <em>YHWH Šālôm</em> (H3068 H7965) — YHWH is Peace — encodes the content of the divine assurance at the encounter. Divine names derived from encounters (El-Roi, Gen 16:14; YHWH-Jireh, Gen 22:14) are theology inscribed in geography: future worshipers at this altar invoke the specific aspect of YHWH revealed here.</p>",
    "25": "<p><em>wayhî ballaylāh hahûʾ wayyōʾmer lô YHWH qaḥ ʾet-par haššôr</em> — 'That same night YHWH said to him: Take your father's bull...' The command is a test of Gideon's covenant loyalty: he must first destroy his own family's Baal altar and Asherah pole before leading Israel against Midian. <em>mizbəaḥ habbāʿal ʾăšer ləʾāḇîkā</em> — 'the Baal altar that belongs to your father' — YHWH's first demand is internal house-cleaning. The Baal altar in Joash's household (Gideon's father) represents the syncretism that caused Israel's oppression in the first place. <em>ʾăšērāh</em> (H842, Asherah — the Canaanite fertility goddess, companion of Baal) represented as a sacred pole — the standard companion-object to Baal altars.</p>",
    "26": "<p><em>ûḇānîtā mizbēaḥ laYHWH ʾĕlōhêkā ʿal-rōʾš hamāʿôz hazzeh bammāʿărāḵāh</em> — 'Build an altar to YHWH your God on top of this stronghold, with the stones laid in order.' <em>māʿôz</em> (H4581, stronghold/refuge/fortress) — the altar is to be built on the highest point of the fortified site, the place of maximum visibility. <em>hammāʿărāḵāh</em> (H4634, in proper order/arrangement) — altar-building has a prescribed form; the stones must be arranged correctly, contrasting with the haphazard idolatry of the Baal altar below. The second bull (seven years old, corresponding to the seven years of Midian's oppression, v25) is to be sacrificed using the wood of the Asherah pole — the instrument of idolatry becomes the fuel for the legitimate sacrifice.</p>",
    "27": "<p><em>wayyiqqaḥ giḏʿôn ʿăśārāh ʾănāšîm mēʿăḇāḏāyw wayyaʿaś kaʾăšer dibbēr ʾēlāyw YHWH</em> — 'Gideon took ten of his servants and did just as YHWH had told him.' Obedience despite fear (<em>wayyîrāʾ ʾet-bêt ʾāḇîw wəʾet-ʾanšê hāʿîr</em> — he feared his father's household and the men of the city) is still counted as obedience. The nighttime action is not a failure of courage but a prudent reading of context — Gideon acts when action is possible. His obedience 'by night' mirrors the Exodus pattern: YHWH struck Egypt at midnight (Exod 12:29); the decisive acts of liberation often occur in darkness.</p>",
    "28": "<p><em>wayyaškîmû ʾanšê hāʿîr babbōqer wəhinnēh nuttaṣ mizbəaḥ habbāʿal wəhāʾăšērāh ʾăšer ʿālāyw kurrāṯāh</em> — 'When the men of the city rose early in the morning, behold, the altar of Baal was torn down (<em>nāṯaṣ</em>), and the Asherah beside it was cut down.' <em>nāṯaṣ</em> (H5422, to tear down/demolish — the same verb used in Deut 7:5 for the commanded destruction of Canaanite altars) — Gideon has obeyed the Deuteronomic altar law. The use of the expected covenant verb confirms that Gideon's action was theologically correct. The Asherah 'cut down' (<em>kārat</em> H3772, to cut off — covenant language used for both cutting covenants and cutting off those who break them) — the religious infrastructure of apostasy has been removed.</p>",
    "29": "<p><em>wayyōʾmərû ʾîš ʾel-rēʿēhû mî ʿāśāh haddāḇār hazzeh wayyidərəšû wayyəḇaqqēšû wayyōʾmərû giḏʿôn ben-yôʾāš ʿāśāh haddāḇār hazzeh</em> — 'They said to one another: Who has done this thing? And when they searched and inquired, they said: Gideon the son of Joash has done this thing.' <em>dāraš</em> (H1875, to seek/inquire/investigate) and <em>bāqaš</em> (H1245, to seek/search) — the community's investigation uses judicial inquiry language: they seek to identify the perpetrator. The identification of Gideon triggers the demand for his death (v30) — destroying an idol is a capital offense in the community that worships it. The confrontation sets up Joash's decisive response.</p>",
    "30": "<p><em>wayyōʾmərû ʾanšê hāʿîr ʾel-yôʾāš hôṣēʾ ʾet-binkā wəyāmōt kî nāṯaṣ ʾet-mizbəaḥ habbāʿal wəkî kārat hāʾăšērāh ʾăšer ʿālāyw</em> — 'The men of the city said to Joash: Bring out your son so that he may die, for he has torn down the altar of Baal and cut down the Asherah beside it.' The death-demand (<em>wəyāmōt</em>) from Israelites defending a Baal altar is the measure of how far Israel has fallen: the covenant people are now prepared to execute one of their own for obeying the covenant law. The demand is made to Joash as head of household — tribal justice operated through family responsibility.</p>",
    "31": "<p><em>wayyōʾmer yôʾāš ləkol ʾăšer ʿāmḏû ʿālāyw hăʾattem tərîḇûn laббāʿal</em> — 'Joash said to all who stood against him: Will you contend for Baal? Will you save him?' Joash's rebuttal is theologically sharp: if Baal is a god, he can defend himself. <em>rîḇ</em> (H7378, to contend/plead a legal case) — Joash reframes the confrontation as a legal case: Baal can be his own plaintiff if his altar has been wronged. <em>ʾăšer yārîḇ lô yûmāt ʿaḏ-habbōqer</em> — 'Whoever contends for him shall be put to death by morning' — a rhetorical reversal: the crowd that came to execute Gideon is now threatened with the same fate if they persist. Joash's argument will later be the standard for prophetic polemic against idols (cf. Isa 44:9-20).</p>",
    "32": "<p><em>wayyiqrāʾ-lô bayyôm hahûʾ yərubbaʿal lēʾmōr yāreb-bô habbāʿal kî nāṯaṣ ʾet-mizbəḥô</em> — 'Therefore on that day Gideon was called Yerubbaal, saying: Let Baal contend against him, because he tore down his altar.' <em>yərubbaʿal</em> (H3378, Yerubba'al — Let Baal contend/plead) — the name is a satirical monument: it commemorates Baal's inability to defend himself. Names from encounters crystallize the theological content of the event; this name crystallizes Baal's impotence. <em>nāṯaṣ</em> (he tore down) — the name will follow Gideon throughout the Gideon-Abimelech narrative as an ironic commentary: the Baal-contender is the one YHWH uses to defeat Midian.</p>",
    "33": "<p><em>wəkol-miḏyān wəʿămālēq ûḇənê-qeḏem neʾespû yaḥdāw wayyaʿăḇərû wayyaḥănû bəʿēmeq yizrəʿēl</em> — 'Then all the Midianites and the Amalekites and the people of the East assembled, crossed the Jordan, and encamped in the Valley of Jezreel.' The gathering of the coalition in the Jezreel Valley is the military situation that requires Gideon's response. <em>ʾāsap</em> (H622, to gather/assemble) and <em>ʿābar</em> (H5674, to cross over — the Jordan crossing that mirrors the Exodus in reverse: enemies coming in to the land) set the scene for the climactic confrontation of chapters 7-8.</p>",
    "34": "<p><em>wərûaḥ YHWH lāḇəšāh ʾet-giḏʿôn wayyitqaʿ baššôpār</em> — 'The Spirit of YHWH clothed Gideon, and he blew the trumpet.' <em>lāḇaš</em> (H3847, to clothe/put on) — the Spirit 'clothing' Gideon is a striking anthropomorphism: Gideon becomes the garment that the Spirit wears, or alternatively, the Spirit enrobes Gideon. The metaphor of Spirit-clothing appears for Amasai (1 Chr 12:18) and Zechariah (2 Chr 24:20). The normal phrase is the Spirit 'coming upon' or 'rushing upon' (<em>ṣālaḥ</em>) someone — the clothing metaphor suggests sustained empowerment for a sustained campaign. The <em>šôpār</em> (H7782, ram's horn trumpet) is the battle signal and the covenant assembly instrument (Exod 19:16; Josh 6:4-5).</p>",
    "35": "<p><em>wayyišlaḥ malʾāḵîm bəkol-mənašše wayyizzāʿēq gam-hûʾ ʾaḥărāyw wayyišlaḥ malʾāḵîm bəʾāšēr ûḇizḇûlun ûḇənaptālî wayyaʿălû liqrāʾtām</em> — 'He sent messengers throughout all Manasseh and they were called out after him; also he sent messengers to Asher, Zebulun, and Naphtali, and they went up to meet them.' The mustering pattern is the <em>šôpār</em> call (v34) followed by messengers (<em>malʾāḵîm</em> H4397) sent outward through the tribes — the same pattern as Saul's muster (1 Sam 11:7). Gideon begins with his own clan (Abiezer, Manasseh) and extends to the northern tribes that had suffered most under Midian's locusts. The willingness of distant tribes to respond to a virtually unknown Gideon testifies to the Spirit's empowerment: the mustering is not merely military but pneumatological.</p>",
    "36": "<p><em>wayyōʾmer giḏʿôn ʾel-hāʾĕlōhîm ʾim-yešəkā môšîaʿ bəyāḏî ʾet-yiśrāʾēl kaʾăšer dibbartā</em> — 'Gideon said to God: If you will save Israel by my hand, as you have spoken...' The fleece test is often cited as exemplary of seeking a sign from God, but the text's tone is ambiguous. Gideon explicitly acknowledges YHWH's promise ('as you have spoken') — the sign is not a demand for proof before obedience but a request for confirmation after commission. <em>gizzāh</em> (H1492, fleece — from <em>gāzaz</em> to shear) — wool as a medium for dew/water is physically apt; wool retains moisture exceptionally well. The reversal in vv37-40 (dry fleece, wet ground; then wet fleece, dry ground) moves beyond natural wool-absorption, making the sign unambiguously supernatural.</p>",
    "37": "<p><em>hinnēh ʾānōkî maṣṣîg ʾet-gizzat haṣṣemer baggōren ʾim-ṭal yihyeh ʿal-haggizzāh ləḇaddāh wəʿal-kol-hāʾāreṣ ḥōreḇ</em> — 'Behold, I am placing a fleece of wool on the threshing floor; if there is dew only on the fleece and it is dry on all the ground, then I shall know that you will save Israel by my hand, as you have spoken.' The threshing floor (<em>gōren</em> H1637) is already an important site: Gideon was threshing wheat in a winepress (6:11) to hide from Midian; the threshing floor is the site of harvest vulnerability and covenant celebration (Ruth 3; Hos 9:1). The sign requested operates in the agricultural domain — the very domain Midian has been destroying. YHWH's control over dew (<em>ṭal</em> H2919, the nightly moisture that is gift and blessing in the arid land) confirms his sovereignty over the harvest economy.</p>",
    "38": "<p><em>wayhî-ḵēn wayyaškēm mimmāḥărāt wayyāzeṣ ʾet-haggizzāh wayyiḵeṣ ṭal min-haggizzāh mālôʾ hassəpel mayim</em> — 'And it was so. When he rose early next morning and squeezed the fleece, he wrung dew from the fleece, a bowlful of water.' <em>māzāh</em> (H4330, to wring out/squeeze) — the physical action confirms the miraculous: so much dew in the fleece that it can be wrung out into a bowl. The bowl of water from a single fleece on a dry night is unambiguous. The sign is generous — not a marginal difference but an abundant overflow. YHWH's confirmation is never stingy.</p>",
    "39": "<p><em>wayyōʾmer giḏʿôn ʾel-hāʾĕlōhîm ʾal-yiḥar ʾappəkā bî waʾăḏabbərāh ʾaḵ-happaʿam</em> — 'Gideon said to God: Let not your anger burn against me; let me speak just once more.' <em>ʾal-yiḥar ʾappəkā</em> (let not your anger burn/glow) — the phrase acknowledges the presumption of asking twice; Gideon is aware he is pushing the limits of divine patience. The politeness formula positions him as supplicant, not demander. Yet the second request is the opposite sign: now the fleece dry and the ground wet. The reversal-sign is epistemically stronger — it eliminates the possibility that the fleece merely absorbed ambient moisture. Gideon's second request, though cautious, is honored without rebuke.</p>",
    "40": "<p><em>wayyaʿaś ʾĕlōhîm kēn ballaylāh hahûʾ</em> — 'God did so that night.' The divine compliance with the second fleece test is notable: YHWH accommodates Gideon's persistent seeking. The phrase <em>wayyaʿas ʾĕlōhîm</em> (God did/acted) is terse and unqualified — no rebuke for asking twice, no reluctance expressed. The pattern of double-testing (dry/wet → wet/dry) ensures that the first result cannot be explained naturally, and its reversal confirms the first as intentional. Gideon's persistent seeking will be vindicated: the man who needed two fleece confirmations will later need only a single overheard dream (7:13-15) to go into battle immediately.</p>"
  }
}

def main():
    c = load_comm('original', 'judges')
    merge_comm(c, ORIGINAL)
    save_comm('original', 'judges', c)
    print(f'judges mkt-original: wrote {sum(len(v) for v in ORIGINAL.values())} verses across ch 4-6')

if __name__ == '__main__':
    main()
